import { showApiError } from '@/api/errorHandler';

const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      retry: 1,
      staleTime: 10_000,
    },
    mutations: {
      onError: (error) => showApiError(error),
    },
  },
});
```

